                parts := strings.Split(scanner.Text(), "\t")
                if len(parts) != 2 {
                        return nil, fmt.Errorf("bad native observation: %q", scanner.Text())
                }
                size, err := strconv.Atoi(parts[1])
                if err != nil {
                        return nil, err
                }
                rows[parts[0]] = size
        }
